from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler

app = Flask(__name__)

# Configure logging
handler = RotatingFileHandler('app.log', maxBytes=10000, backupCount=1)
handler.setLevel(logging.INFO)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
app.logger.addHandler(handler)

def log_request_info():
    app.logger.info('Headers: %s', request.headers)
    app.logger.info('Body: %s', request.get_data())
    # Do not log sensitive information like passwords or tokens

@app.before_request
def before_request():
    log_request_info()

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    # Passwords and tokens should not be logged
    password = data.get('password')
    # Simulate authentication
    if username == 'admin' and password == 'secret':
        response = jsonify({'message': 'Login successful'})
        response.status_code = 200
    else:
        response = jsonify({'message': 'Login failed'})
        response.status_code = 401
    app.logger.info('Response: %s', response.get_data(as_text=True))
    return response

@app.route('/data', methods=['GET'])
def get_data():
    user_info = request.headers.get('User-Info', 'anonymous')
    app.logger.info('User Info: %s', user_info)
    response = jsonify({'data': 'Here is your data'})
    app.logger.info('Response: %s', response.get_data(as_text=True))
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    app.logger.error('Error: %s', str(e))
    response = jsonify({'message': 'Internal server error'})
    response.status_code = 500
    return response

if __name__ == '__main__':
    app.run(debug=True)